// BotState is the resolver for the BotState field.
func (r *queryResolver) BotState(ctx context.Context, input model.QueryBotStateInput) (*model.BotState, error) {
	_, ok := auth.GetUserFromContext(ctx)
	if !ok {
		return nil, mowerror.New(mowerror.PermissionDenied, "unauthorized")
	}
	if input.BotID <= 0 {
		return nil, mowerror.New(mowerror.InvalidArgument, "botId is required")
	}

	request := &stypes.GetBotStateRequest{
		BotID: int32(input.BotID),
	}
	response, err := r.StrategySvc.GetBotState(ctx, request)
	if err != nil {
		return nil, err
	}

	var portfolio *model.BotPortfolio
	if response.Portfolio != nil {
		assets := make([]*model.BotPortfolioAsset, 0, len(response.Portfolio.Assets))
		for _, a := range response.Portfolio.Assets {
			assets = append(assets, &model.BotPortfolioAsset{
				Exchange:   a.Exchange,
				WalletType: converter.WalletTypeTypes2Gql(a.WalletType),
				Asset:      a.Asset,
				Free:       a.Free,
				Frozen:     a.Frozen,
				UpdatedTs:  int(a.UpdatedTs),
			})
		}

		positions := make([]*model.BotPortfolioPosition, 0, len(response.Portfolio.Positions))
		for _, p := range response.Portfolio.Positions {
			positions = append(positions, &model.BotPortfolioPosition{
				Exchange:   p.Exchange,
				Symbol:     p.Symbol,
				MarketType: converter.MarketTypeTypes2Gql(p.MarketType),
				Side:       converter.PositionSideTypes2Gql(p.Side),
				Qty:        p.Qty,
				AvgPrice:   p.AvgPrice,
				UpdatedTs:  int(p.UpdatedTs),
				Leverage:   int(p.Leverage),
			})
		}

		portfolio = &model.BotPortfolio{
			Assets:    assets,
			Positions: positions,
			Ts:        int(response.Portfolio.Ts),
		}
	}

	return &model.BotState{
		BotStatus:           converter.BotStatusTypes2Gql(response.BotStatus),
		ExecutorStatus:      response.ExecutorStatus,
		RunErr:              &response.RunErr,
		JsRunnerStatus:      response.JsRunnerStatus,
		Portfolio:           portfolio,
		SignalAvgDurationMs: func() *int { v := int(response.SignalAvgDurationMs); return &v }(),
		SignalAvgLatencyMs:  func() *int { v := int(response.SignalAvgLatencyMs); return &v }(),
		LastSignalTs:        func() *int { v := int(response.LastSignalTs); return &v }(),
	}, nil
}

// BotOrders is the resolver for the BotOrders field.
func (r *queryResolver) BotOrders(ctx context.Context, input model.QueryBotOrdersInput) (*model.BotOrdersConnection, error) {
	_, ok := auth.GetUserFromContext(ctx)
	if !ok {
		return nil, mowerror.New(mowerror.PermissionDenied, "unauthorized")
	}
	// includeFinished=false 时，默认只返回未完成订单（与 market.Orders 行为一致）
	var statuses []ctypes.OrderStatus
	if !input.IncludeFinished {
		statuses = []ctypes.OrderStatus{
			ctypes.OrderStatusNew,
			ctypes.OrderStatusPending,
			ctypes.OrderStatusWorking,
			ctypes.OrderStatusPartialDone,
		}
	}

	request := &stypes.ListBotOrdersRequest{
		BotID:    int32(input.BotID),
		Symbol:   input.Symbol,
		Page:     int32(input.Page),
		Size:     int32(input.Size),
		Statuses: statuses,
	}
	if input.OrderType != nil {
		ot := converter.OrderTypeGql2Types(input.OrderType)
		request.OrderType = &ot
	}
	response, err := r.StrategySvc.ListBotOrders(ctx, request)
	if err != nil {
		return nil, err
	}

	orders := make([]*model.Order, 0, len(response.Orders))
	for _, order := range response.Orders {
		orders = append(orders, converter.OrderTypes2Gql(order))
	}

	return &model.BotOrdersConnection{
		TotalCount: int(response.TotalCount),
		List:       orders,
	}, nil
}

