// BotLogs is the resolver for the BotLogs field.
func (r *queryResolver) BotLogs(ctx context.Context, input model.QueryBotLogsInput) (*model.BotLogsConnection, error) {
	_, ok := auth.GetUserFromContext(ctx)
	if !ok {
		return nil, mowerror.New(mowerror.PermissionDenied, "unauthorized")
	}
	limitVal := int32(100)
	if input.Limit != nil {
		limitVal = int32(*input.Limit)
	}

	request := &stypes.ListBotLogsRequest{
		BotID: int32(input.BotID),
		Limit: limitVal,
	}
	if input.Cursor != nil {
		request.Cursor = input.Cursor
	}
	if input.StartTs != nil {
		start := int64(*input.StartTs)
		request.StartTime = &start
	}
	if input.EndTs != nil {
		end := int64(*input.EndTs)
		request.EndTime = &end
	}
	if input.Level != nil {
		request.Level = input.Level
	}

	response, err := r.StrategySvc.ListBotLogs(ctx, request)
	if err != nil {
		return nil, err
	}

	logs := make([]*model.BotLog, 0, len(response.Logs))
	for _, logEntry := range response.Logs {
		logs = append(logs, converter.BotLogTypes2Gql(logEntry))
	}

	var nextCursor *string
	if response.NextCursor != nil {
		nextCursor = response.NextCursor
	}
	return &model.BotLogsConnection{
		List:       logs,
		NextCursor: nextCursor,
	}, nil
}

// BotSignalFlow is the resolver for the BotSignalFlow field.
func (r *queryResolver) BotSignalFlow(ctx context.Context, input model.QueryBotSignalFlowInput) (*model.BotSignalFlowConnection, error) {
	_, ok := auth.GetUserFromContext(ctx)
	if !ok {
		return nil, mowerror.New(mowerror.PermissionDenied, "unauthorized")
	}
	if input.BotID <= 0 {
		return nil, mowerror.New(mowerror.InvalidArgument, "botId is required")
	}

	limitVal := int32(200)
	if input.Limit != nil && *input.Limit > 0 {
		limitVal = int32(*input.Limit)
	}

	request := &stypes.QueryBotSignalFlowRequest{
		BotID: int32(input.BotID),
		Limit: limitVal,
	}
	if input.SignalType != nil {
		t := converter.SignalTypeGql2Types(*input.SignalType)
		request.SignalType = &t
	}
	if input.StartTsMs != nil {
		start := int64(*input.StartTsMs)
		request.StartTsMs = &start
	}
	if input.StartID != nil {
		startID := int64(*input.StartID)
		request.StartID = &startID
	}

	response, err := r.StrategySvc.QueryBotSignalFlow(ctx, request)
	if err != nil {
		return nil, err
	}

	events := make([]*model.BotSignalRecord, 0, len(response.Events))
	for _, evt := range response.Events {
		events = append(events, &model.BotSignalRecord{
			ID:           strconv.FormatInt(evt.ID, 10),
			BotID:        int(evt.BotID),
			AccountID:    evt.AccountID,
			Exchange:     evt.Exchange,
			Stream:       evt.Stream,
			Topic:        evt.Topic,
			EventKind:    evt.EventKind,
			TsMs:         int(evt.TsMs),
			InboundAtMs:  int(evt.InboundAtMs),
			OutboundAtMs: int(evt.OutboundAtMs),
			ReceiveAtMs:  int(evt.ReceiveAtMs),
			IngestAtMs:   int(evt.IngestAtMs),
			PayloadJSON:  evt.PayloadJSON,
		})
	}

	return &model.BotSignalFlowConnection{
		Events: events,
		NextID: strconv.FormatInt(response.NextID, 10),
	}, nil
}

// BotSignalStats is the resolver for the BotSignalStats field.
func (r *queryResolver) BotSignalStats(ctx context.Context, startTs int, endTs int, botID *int) (*model.BotSignalStats, error) {
	_, ok := auth.GetUserFromContext(ctx)
	if !ok {
		return nil, mowerror.New(mowerror.PermissionDenied, "unauthorized")
	}
	req := &stypes.GetBotStatsRequest{
		StartTs: int64(startTs),
		EndTs:   int64(endTs),
	}
	if botID != nil && *botID > 0 {
		bid := int32(*botID)
		req.BotID = &bid
	}
	resp, err := r.StrategySvc.GetBotStats(ctx, req)
	if err != nil {
		return nil, err
	}
	if resp == nil || len(resp.Stats) == 0 {
		return &model.BotSignalStats{Stats: []*model.BotSignalStat{}}, nil
	}
	stats := make([]*model.BotSignalStat, 0, len(resp.Stats))
	for _, s := range resp.Stats {
		stats = append(stats, &model.BotSignalStat{
			BotID:        int(s.BotID),
			Stream:       s.Stream,
			EventCount:   int(s.EventCount),
			AvgLatencyMs: s.AvgLatencyMs,
			MaxLatencyMs: s.MaxLatencyMs,
		})
	}
	return &model.BotSignalStats{Stats: stats}, nil
}

// BotMetrics is the resolver for the BotMetrics field.
func (r *queryResolver) BotMetrics(ctx context.Context, input model.QueryBotMetricsInput) (*model.BotMetrics, error) {
	_, ok := auth.GetUserFromContext(ctx)
	if !ok {
		return nil, mowerror.New(mowerror.PermissionDenied, "unauthorized")
	}
	var symbol *ctypes.Symbol
	if input.Symbol != nil {
		sym, err := ctypes.ParseSymbol(*input.Symbol)
		if err != nil {
			return nil, err
		}
		symbol = &sym
	}
	dim := converter.MetricsDimensionGql2Types(input.Dimension)
	req := &stypes.QueryBotMetricsRequest{
		BotID:     int32(input.BotID),
		Dimension: dim,
		Symbol:    symbol,
		StartTs:   types.PIntToPInt64(input.StartTs),
		EndTs:     types.PIntToPInt64(input.EndTs),
	}
	pb, err := r.StrategySvc.QueryBotMetrics(ctx, req)
	if err != nil {
		return nil, err
	}

	if pb == nil {
		return nil, nil
	}
	symbols := make([]*model.SymbolMetrics, 0, len(pb.Symbols))
	for _, s := range pb.Symbols {
		symbols = append(symbols, converter.SymbolMetricsTypes2Gql(s))
	}
	sharpe := pb.Sharpe
	if math.IsNaN(sharpe) {
		sharpe = 0
	}
	sortino := pb.Sortino
	if math.IsInf(sortino, 1) {
		sortino = 0
	}
	return &model.BotMetrics{
		AccountID:             pb.AccountID,
		BotID:                 int(pb.BotID),
		Dimension:             converter.MetricsDimensionTypes2Gql(pb.Dimension),
		SymbolsFilter:         pb.SymbolsFilter,
		Cagr:                  pb.Cagr,
		Sharpe:                sharpe,
		Sortino:               sortino,
		MaxDrawdown:           pb.MaxDrawdown,
		TimeUnderWaterSeconds: int(pb.TimeUnderWaterSeconds),
		Calmar:                pb.Calmar,
		WinRate:               pb.WinRate,
		ProfitFactor:          pb.ProfitFactor,
		RollingSharpe:         pb.RollingSharpe,
		AvgSlippageBps:        pb.AvgSlippageBps,
		FeeRatio:              pb.FeeRatio,
		MaxConsecutiveLoss:    int(pb.MaxConsecutiveLoss),
		StartTs:               int(pb.StartTs),
		EndTs:                 int(pb.EndTs),
		Symbols:               symbols,
	}, nil
}

// Bot returns action.BotResolver implementation.
func (r *Resolver) Bot() action.BotResolver { return &botResolver{r} }

type botResolver struct{ *Resolver }
